from __future__ import annotations

import os
from dataclasses import dataclass
from typing import Mapping
from urllib.parse import urlparse

from server.config import BaseConfig, get_app_config
from server.utils.logging import get_app_logger

app_logger = get_app_logger()


@dataclass(frozen=True)
class StartupSafetyAlert:
    code: str
    message: str


def _env_name(environ: Mapping[str, str] | None = None) -> str:
    env = environ if environ is not None else os.environ
    return (env.get("FASTAPI_ENV") or "development").strip().lower()


def _is_production(config: BaseConfig, environ: Mapping[str, str] | None = None) -> bool:
    return _env_name(environ) == "production" or not bool(getattr(config, "IS_DEV", False))


def _is_local_or_insecure_url(value: str) -> bool:
    parsed = urlparse((value or "").strip())
    host = (parsed.hostname or "").lower()
    return parsed.scheme == "http" or host in {"localhost", "127.0.0.1", "0.0.0.0"}


def collect_startup_safety_alerts(
    config: BaseConfig | None = None,
    *,
    role: str = "main",
    environ: Mapping[str, str] | None = None,
) -> list[StartupSafetyAlert]:
    """
    Return startup safety alerts for risky runtime configuration.

    These checks intentionally do not mutate configuration or raise. Callers can
    log the returned alerts while allowing the normal startup path to continue.
    """
    cfg = config if config is not None else get_app_config()
    alerts: list[StartupSafetyAlert] = []

    for setting_name in ("SECRET_KEY", "JWT_SECRET_KEY"):
        secret_value = str(getattr(cfg, setting_name, "") or "")
        if len(secret_value.encode("utf-8")) < 32:
            alerts.append(
                StartupSafetyAlert(
                    code=f"{setting_name.lower()}.weak",
                    message=f"{setting_name} is missing or shorter than 32 bytes.",
                )
            )

    cors_origins = [str(origin).strip() for origin in (cfg.CORS_ALLOWED_ORIGINS or []) if str(origin).strip()]
    if not cors_origins:
        alerts.append(
            StartupSafetyAlert(
                code="cors.empty",
                message="CORS_ALLOWED_ORIGINS is empty; browser clients may be unable to reach the API.",
            )
        )

    if not _is_production(cfg, environ):
        return alerts

    if not bool(cfg.JWT_COOKIE_SECURE):
        alerts.append(
            StartupSafetyAlert(
                code="jwt_cookie.insecure",
                message="JWT_COOKIE_SECURE is disabled while running in production.",
            )
        )

    if any(origin == "*" for origin in cors_origins):
        alerts.append(
            StartupSafetyAlert(
                code="cors.wildcard",
                message="CORS_ALLOWED_ORIGINS includes '*' while running in production.",
            )
        )

    for setting_name in (
        "BACKEND_PUBLIC_BASE_URL",
        "FRONTEND_PUBLIC_BASE_URL",
        "GAME_WS_PUBLIC_BASE_URL",
        "CHAT_WS_PUBLIC_BASE_URL",
    ):
        setting_value = str(getattr(cfg, setting_name, "") or "")
        if _is_local_or_insecure_url(setting_value):
            alerts.append(
                StartupSafetyAlert(
                    code=f"{setting_name.lower()}.insecure",
                    message=f"{setting_name} is local or uses plain HTTP in production: {setting_value}",
                )
            )

    if str(getattr(cfg, "DEV_ADMIN_TOKEN", "") or "").strip():
        alerts.append(
            StartupSafetyAlert(
                code="dev_admin_token.enabled",
                message="DEV_ADMIN_TOKEN is set while running in production.",
            )
        )

    normalized_role = role.strip().lower()
    if normalized_role == "main" and not str(getattr(cfg, "GAME_SERVER_CREDENTIALS_JSON", "") or "").strip():
        alerts.append(
            StartupSafetyAlert(
                code="game_server.credentials_missing",
                message="GAME_SERVER_CREDENTIALS_JSON is empty; game server registry authentication is unavailable.",
            )
        )

    if normalized_role == "game_server":
        server_id = str(getattr(cfg, "GAME_SERVER_SELF_ID", "") or "").strip()
        signing_secret = str(getattr(cfg, "GAME_SERVER_SELF_SIGNING_SECRET", "") or "").strip()
        if not server_id or not signing_secret:
            alerts.append(
                StartupSafetyAlert(
                    code="game_server.self_credentials_missing",
                    message=(
                        "GAME_SERVER_SELF_ID or GAME_SERVER_SELF_SIGNING_SECRET is empty; "
                        "registry heartbeat will be disabled."
                    ),
                )
            )

    return alerts


def emit_startup_safety_alerts(*, role: str = "main") -> list[StartupSafetyAlert]:
    """Log startup safety alerts and never raise from the alerting path."""
    try:
        alerts = collect_startup_safety_alerts(role=role)
    except Exception as exc:
        alert = StartupSafetyAlert(
            code="config.load_failed",
            message=f"Unable to evaluate startup safety alerts: {exc}",
        )
        app_logger.warning("[StartupSafety] %s: %s", alert.code, alert.message)
        return [alert]

    for alert in alerts:
        app_logger.warning("[StartupSafety] %s: %s", alert.code, alert.message)

    if not alerts:
        app_logger.info("[StartupSafety] No startup safety alerts for role=%s.", role)

    return alerts

